#include<bits/stdc++.h>
using namespace std;
constexpr int N=1e6+10;
int n,m,a[N],l[N],r[N],k[N],u[N],x[N];
int q1[N],q2[N],v[N];
int cur,cur1,cur2;
char op[N];
set<int> st;
map<int,int> mp;
struct segment_tree
{
    struct node
    {
        int sum;
        int lson,rson;
    }a[60*N];
    int root[N*4],cnt;
    segment_tree():cnt(0){}
    void update(int &p,int l,int r,int x,int v)
    {
        if(p==0)
        {
            p=++cnt;
        }
        a[p].sum+=v;
        if(l==r)
        {
            return;
        }
        int mid=(l+r)>>1;
        if(x<=mid)
        {
            update(a[p].lson,l,mid,x,v);
        }
        else
        {
            update(a[p].rson,mid+1,r,x,v);
        }
    }
}t;
int lowbit(int x)
{
    return x&-x;
}
void update(int o,int x,int v)
{
    for(;o<=n;o+=lowbit(o))
    {
        t.update(t.root[o],1,n,x,v);
    }
}
void gtv(int o,int a[],int &p)
{
    p=0;
    for(;o;o-=lowbit(o))
    {
        a[++p]=t.root[o];
    }
}
int query(int l,int r,int k)
{
    if(l==r)
    {
        return l;
    }
    int mid=(l+r)>>1,siz=0;
    for(int i=1;i<=cur1;i++)
    {
        siz+=t.a[t.a[q1[i]].lson].sum;
    }
    for(int i=1;i<=cur2;i++)
    {
        siz-=t.a[t.a[q2[i]].lson].sum;
    }
    if(k<=siz)
    {
        for(int i=1;i<=cur1;i++)
        {
            q1[i]=t.a[q1[i]].lson;
        }
        for(int i=1;i<=cur2;i++)
        {
            q2[i]=t.a[q2[i]].lson;
        }
        return query(l,mid,k);
    }
    else
    {
        for(int i=1;i<=cur1;i++)
        {
            q1[i]=t.a[q1[i]].rson;
        }
        for(int i=1;i<=cur2;i++)
        {
            q2[i]=t.a[q2[i]].rson;
        }
        return query(mid+1,r,k-siz);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        st.insert(a[i]);
    }
    for(int i=1;i<=m;i++)
    {
        cin>>op[i];
        if(op[i]=='C')
        {
            scanf("%d%d",&u[i],&x[i]);
            st.insert(x[i]);
        }
        else
        {
            scanf("%d%d%d",&l[i],&r[i],&k[i]);
        }
    }
    for(int i:st)
    {
        mp[i]=++cur;
        v[cur]=i;
    }
    for(int i=1;i<=n;i++)
    {
        a[i]=mp[a[i]];
    }
    for(int i=1;i<=m;i++)
    {
        if(op[i]=='C')
        {
            x[i]=mp[x[i]];
        }
    }
    n+=m;
    for(int i=1;i<=n;i++)
    {
        update(i,a[i],1);
    }
    for(int i=1;i<=m;i++)
    {
        if(op[i]=='C')
        {
            update(u[i],a[u[i]],-1);
            a[u[i]]=x[i];
            update(u[i],a[u[i]],1);
        }
        else
        {
            gtv(r[i],q1,cur1);
            gtv(l[i]-1,q2,cur2);
            printf("%d\n",v[query(1,n,k[i])]);
        }
    }
    return 0;
}
